from __future__ import annotations

import hashlib
import json


class AuditLogWriter:
    def __init__(self, sink):
        self.sink = sink
        self.next_sequence = 1

    def write(self, actor: str, action: str):
        base = {'sequence': self.next_sequence, 'actor': actor, 'action': action}
        checksum = hashlib.sha256(json.dumps(base, sort_keys=True).encode()).hexdigest()
        row = dict(base)
        row['checksum'] = checksum
        self.next_sequence += 1
        self.sink.append(row.copy())
        return row.copy()

